import sys
import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError, TopicAlreadyExistsError
import json


def create_admin_client(bootstrap_servers):
    try:
        admin_client = KafkaAdminClient(
            bootstrap_servers=bootstrap_servers,
            client_id='kafka-admin-tool'
        )
        return admin_client
    except Exception as e:
        print(f"Error creating admin client: {e}")
        sys.exit(1)


def create_topic(admin_client, topic_name, num_partitions, replication_factor, config):
    try:
        topic_config = {}
        if config:
            try:
                topic_config = json.loads(config)
            except json.JSONDecodeError:
                for item in config.split(','):
                    if '=' in item:
                        key, value = item.split('=', 1)
                        topic_config[key.strip()] = value.strip()
        
        new_topic = NewTopic(
            name=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_config
        )
        
        result = admin_client.create_topics([new_topic], validate_only=False)
        
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' created successfully")
            except TopicAlreadyExistsError:
                print(f"Topic '{topic}' already exists")
            except Exception as e:
                print(f"Failed to create topic '{topic}': {e}")
                
    except Exception as e:
        print(f"Error creating topic: {e}")


def delete_topic(admin_client, topic_names):
    try:
        result = admin_client.delete_topics(topic_names)
        
        for topic, future in result.items():
            try:
                future.result()
                print(f"Topic '{topic}' deleted successfully")
            except Exception as e:
                print(f"Failed to delete topic '{topic}': {e}")
                
    except Exception as e:
        print(f"Error deleting topics: {e}")


def list_topics(admin_client):
    try:
        topics = admin_client.list_topics()
        print("Available topics:")
        for topic in topics:
            print(f"  - {topic}")
    except Exception as e:
        print(f"Error listing topics: {e}")


def describe_topic(admin_client, topic_name):
    try:
        metadata = admin_client._client.cluster
        metadata.request_update()
        
        topic_metadata = metadata.topics()
        
        if topic_name in topic_metadata:
            topic_info = topic_metadata[topic_name]
            print(f"\nTopic: {topic_name}")
            print(f"Partitions: {len(topic_info)}")
            
            for partition_id, partition_metadata in topic_info.items():
                print(f"\n  Partition {partition_id}:")
                print(f"    Leader: {partition_metadata.leader}")
                print(f"    Replicas: {partition_metadata.replicas}")
                print(f"    ISR: {partition_metadata.isr}")
        else:
            print(f"Topic '{topic_name}' not found")
            
    except Exception as e:
        print(f"Error describing topic: {e}")


def alter_topic_config(admin_client, topic_name, config):
    try:
        topic_config = {}
        if config:
            try:
                topic_config = json.loads(config)
            except json.JSONDecodeError:
                for item in config.split(','):
                    if '=' in item:
                        key, value = item.split('=', 1)
                        topic_config[key.strip()] = value.strip()
        
        config_resource = ConfigResource(
            ConfigResourceType.TOPIC,
            topic_name,
            configs=topic_config
        )
        
        result = admin_client.alter_configs([config_resource])
        
        for resource, future in result.items():
            try:
                future.result()
                print(f"Configuration for topic '{topic_name}' updated successfully")
            except Exception as e:
                print(f"Failed to update configuration for topic '{topic_name}': {e}")
                
    except Exception as e:
        print(f"Error altering topic configuration: {e}")


def describe_topic_config(admin_client, topic_name):
    try:
        config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
        result = admin_client.describe_configs([config_resource])
        
        for resource, future in result.items():
            try:
                config = future.result()
                print(f"\nConfiguration for topic '{topic_name}':")
                for config_name, config_value in config.items():
                    print(f"  {config_name}: {config_value.value} (source: {config_value.source})")
            except Exception as e:
                print(f"Failed to describe configuration for topic '{topic_name}': {e}")
                
    except Exception as e:
        print(f"Error describing topic configuration: {e}")


def create_partitions(admin_client, topic_name, total_count):
    try:
        from kafka.admin import NewPartitions
        
        new_partitions = {topic_name: NewPartitions(total_count=total_count)}
        result = admin_client.create_partitions(new_partitions, validate_only=False)
        
        for topic, future in result.items():
            try:
                future.result()
                print(f"Partitions for topic '{topic}' increased to {total_count}")
            except Exception as e:
                print(f"Failed to create partitions for topic '{topic}': {e}")
                
    except Exception as e:
        print(f"Error creating partitions: {e}")


def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers (comma-separated)')
    
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    create_parser = subparsers.add_parser('create', help='Create a new topic')
    create_parser.add_argument('--topic', required=True, help='Topic name')
